#!/usr/bin/env python3
"""Deploy UPL contracts to Hyperliquid HyperEVM (Chain ID: 999)"""
from web3 import Web3
from eth_account import Account
import json

MNEMONIC = "inside post tool solar phone biology render blade broken draw hockey senior"

PRIVACY_RELAYER_BYTECODE = ""

STEALTH_REGISTRY_BYTECODE = ""

RPC   = "https://rpc.hyperliquid.xyz/evm"
CHAIN_ID = 999

def deploy():
    print("=" * 55)
    print("UPL DEPLOYMENT — HYPERLIQUID HyperEVM (Chain 999)")
    print("=" * 55)

    w3 = Web3(Web3.HTTPProvider(RPC, request_kwargs={"timeout": 60}))
    print(f"Connected: {w3.is_connected()}")

    Account.enable_unaudited_hdwallet_features()
    account = Account.from_mnemonic(MNEMONIC)

    balance  = w3.eth.get_balance(account.address)
    gas_price = max(w3.eth.gas_price, w3.to_wei(1, "gwei"))
    nonce    = w3.eth.get_transaction_count(account.address)

    print(f"Deployer : {account.address}")
    print(f"Balance  : {w3.from_wei(balance, 'ether')} HYPE")
    print(f"Gas price: {w3.from_wei(gas_price, 'gwei'):.4f} gwei")
    print(f"Nonce    : {nonce}")

    deployed = {}

    for i, (name, bytecode, gas_limit) in enumerate([
        ("PrivacyRelayer",        PRIVACY_RELAYER_BYTECODE, 600_000),
        ("StealthAddressRegistry", STEALTH_REGISTRY_BYTECODE, 500_000),
    ], 1):
        print(f"\n[{i}/2] Deploying {name}...")
        try:
            tx = {
                "chainId": CHAIN_ID,
                "gas": gas_limit,
                "gasPrice": gas_price,
                "nonce": nonce,
                "data": "0x" + bytecode,
            }
            signed  = account.sign_transaction(tx)
            tx_hash = w3.eth.send_raw_transaction(signed.rawTransaction)
            print(f"  TX   : {tx_hash.hex()}")
            print(f"  Waiting for confirmation (300s timeout)…")
            receipt = w3.eth.wait_for_transaction_receipt(tx_hash, timeout=300)
            if receipt.status == 1:
                deployed[name] = receipt.contractAddress
                print(f"  LIVE : {receipt.contractAddress}  (gas used: {receipt.gasUsed:,})")
            else:
                print(f"  FAILED (status=0)")
            nonce += 1
        except Exception as e:
            print(f"  ERROR: {e}")
            nonce += 1

    final_bal = w3.eth.get_balance(account.address)
    print(f"\nGas spent : {w3.from_wei(balance - final_bal, 'ether'):.8f} HYPE")
    print(f"Remaining : {w3.from_wei(final_bal, 'ether'):.8f} HYPE")

    print("\n--- RESULT ---")
    for name, addr in deployed.items():
        print(f"  {name}: {addr}")
        print(f"  Explorer: https://purrsec.com/address/{addr}")

    with open("/app/contracts/deployed_hyperliquid.json", "w") as f:
        json.dump({"network": "hyperliquid", "chain_id": CHAIN_ID,
                   "deployer": account.address, "contracts": deployed}, f, indent=2)

    return deployed

if __name__ == "__main__":
    deploy()
